module RefModule(
   input                clk,
   input                rst,
   input                load,
   input                en,
   input      [3:0]     D,

   output reg [3:0]     Q
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst) Q <= 4'd0;
        else if (load) Q <= D;
        else if (en) Q <= Q - 1;
    end
endmodule
